{
  for (auto* bb : L->blocks()) {
    for (auto& I : *bb) {
      if (auto si = dyn_cast<StoreInst>(&I)) {
        if (si == excluded)
          continue;
        // Conservative: any other store may alias with our ptr.
        return true;
      }
      if (isa<CallBase>(I))
        return true;
    }
  }
  return false;
}

// Returns true if `L` writes to `ptr` (other than at `excluded`) via a store
// whose pointer might alias `ptr`.  Two pointers are considered to "not alias"
// if both are derived from different allocas (we use the alloca base).
bool
loopMayAliasStoreToPtr(Loop* L, Value* ptr, StoreInst* excluded)
{
  // Find the base alloca of `ptr` (if any).
  Value* base = ptr;
  while (auto gep = dyn_cast<GetElementPtrInst>(base))
    base = gep->getPointerOperand();
  AllocaInst* alloca = dyn_cast<AllocaInst>(base);

  for (auto* bb : L->blocks()) {
    for (auto& I : *bb) {
      if (auto si = dyn_cast<StoreInst>(&I)) {
        if (si == excluded)
          continue;
        Value* otherBase = si->getPointerOperand();
        while (auto gep = dyn_cast<GetElementPtrInst>(otherBase))
          otherBase = gep->getPointerOperand();
        if (alloca && isa<AllocaInst>(otherBase) && otherBase != alloca)
          continue; // different allocas don't alias
        return true; // conservatively alias
      }
      if (isa<CallBase>(I))
        return true;
    }
  }
  return false;
}

